const raw = ($input.first().json.chatInput || '').trim();
if (!raw) throw new Error('Please paste a list of company names — one per line, or comma-separated.');

let names;
const lines = raw.split(/\r?\n/).map(function(l){return l.trim();}).filter(Boolean);
if (lines.length > 1) {
  names = lines;
} else {
  names = raw.split(',').map(function(s){return s.trim();}).filter(Boolean);
}

if (names.length === 0) throw new Error('No company names found in your input.');
if (names.length > 50) throw new Error('Maximum 50 companies per lookup. You submitted ' + names.length + '.');

return names.map(function(name) {
  return {json: {companyName: name.replace(/^"|"$/g, '')}};
});

const parseNamesItems = $('Parse Names').all();
const chResults = $input.all();

return chResults.map(function(chItem, idx) {
  const companyName = (parseNamesItems[idx] && parseNamesItems[idx].json.companyName) || '';
  const searchItems = (chItem.json.items || []).slice(0, 5);

  if (!companyName || searchItems.length === 0) {
    return {json: {companyName: companyName, ollamaBody: null, noResults: true}};
  }

  const candidates = searchItems.map(function(item, i) {
    return (i+1)+'. "'+item.title+'" | Reg: '+item.company_number+' | Status: '+(item.company_status||'Unknown')+' | '+(item.address_snippet||'');
  }).join('\n');

  const prompt = 'You are matching a company name to UK Companies House registrations.\n\n'
    + 'Search term: "'+companyName+'"\n\n'
    + 'Companies House search results:\n'+candidates+'\n\n'
    + 'For each result, rate how likely it is to be the company we are searching for, with a confidence score from 0 to 100.\n'
    + 'Consider:\n'
    + '- Exact name match scores very high (90-100)\n'
    + '- Same name with Ltd/Limited/PLC/Co variation scores high (80-95)\n'
    + '- Likely same company but trading name vs registered name scores medium-high (60-80)\n'
    + '- Partial match or similar but potentially different company scores low (20-50)\n'
    + '- Prefer Active companies over Dissolved where confidence is similar\n\n'
    + 'Respond with a JSON array ONLY, no other text or explanation:\n'
    + '[{"rank":1,"company_number":"12345678","company_name":"EXAMPLE LIMITED","status":"active","confidence":95,"reason":"Exact name match, active company"}]\n\n'
    + 'Include all results with confidence >= 25. Always include at least the top result, even if confidence is low.';

  const body = JSON.stringify({model: 'qwen3.5:27b', prompt: prompt, stream: false, think: false});
  return {json: {companyName: companyName, ollamaBody: body, noResults: false}};
});

const prepItems = $('Prepare Prompt').all();
const ollamaResults = $input.all();
const chBase = 'https://find-and-update.company-information.service.gov.uk/company/';

return ollamaResults.map(function(ollamaItem, idx) {
  const companyName = (prepItems[idx] && prepItems[idx].json.companyName) || '';
  const noResults = (prepItems[idx] && prepItems[idx].json.noResults) || false;

  if (noResults) {
    return {json: {companyName: companyName, matches: [], noResult: true}};
  }

  const response = (ollamaItem.json.response || '').trim();
  let matches = [];
  try {
    const jsonMatch = response.match(/\[[\s\S]*\]/);
    if (jsonMatch) matches = JSON.parse(jsonMatch[0]);
  } catch(e) {}

  return {json: {
    companyName: companyName,
    matches: matches.map(function(m) {
      const conf = parseInt(m.confidence) || 0;
      const lvl = conf >= 80 ? 'high' : conf >= 50 ? 'medium' : 'low';
      return {
        company_number: (m.company_number || '').trim(),
        company_name: m.company_name || '',
        status: m.status || 'Unknown',
        confidence: conf,
        confidence_level: lvl,
        reason: m.reason || '',
        ch_url: chBase + (m.company_number || '').trim()
      };
    }).sort(function(a,b){return b.confidence - a.confidence;}),
    noResult: matches.length === 0
  }};
});

const allResults = ($input.first().json.allResults || []);
const date = new Date().toLocaleDateString('en-GB');

const C = {
  high:   {bg:'#d4edda', fg:'#155724', label:'High'},
  medium: {bg:'#fff3cd', fg:'#856404', label:'Medium'},
  low:    {bg:'#f8d7da', fg:'#721c24', label:'Low'}
};

let htmlRows = '';
const csvLines = ['"Searched Name","Company Number","Registered Name","Confidence","Status","Confidence Level","Companies House URL"'];

for (const result of allResults) {
  const name = result.companyName || '';

  if (!result.matches || result.matches.length === 0) {
    htmlRows += '<tr>'
      + '<td style="padding:8px;border-bottom:1px solid #ddd;vertical-align:top">'+name+'</td>'
      + '<td colspan="5" style="padding:8px;border-bottom:1px solid #ddd;color:#6c757d;font-style:italic">No matches found</td>'
      + '</tr>';
    csvLines.push('"'+name.replace(/"/g,'""')+'",,,,"","No match",""');
    continue;
  }

  result.matches.forEach(function(m, idx) {
    const c = C[m.confidence_level] || C.low;
    const nameCell = idx === 0
      ? '<td style="padding:8px;border-bottom:1px solid #ddd;vertical-align:top" rowspan="'+result.matches.length+'">'+name+'</td>'
      : '';
    htmlRows += '<tr>'
      + nameCell
      + '<td style="padding:8px;border-bottom:1px solid #ddd"><a href="'+m.ch_url+'" style="color:#2c3e50">'+m.company_number+'</a></td>'
      + '<td style="padding:8px;border-bottom:1px solid #ddd">'+m.company_name+'</td>'
      + '<td style="padding:8px;border-bottom:1px solid #ddd;text-align:center;background:'+c.bg+';color:'+c.fg+'"><strong>'+m.confidence+'%</strong></td>'
      + '<td style="padding:8px;border-bottom:1px solid #ddd">'+m.status+'</td>'
      + '<td style="padding:8px;border-bottom:1px solid #ddd;font-size:11px">'+m.reason+'</td>'
      + '</tr>';
    csvLines.push('"'+name.replace(/"/g,'""')+'","'+m.company_number+'","'+m.company_name.replace(/"/g,'""')+'","'+m.confidence+'%","'+m.status+'","'+c.label+'","'+m.ch_url+'"');
  });
}

const total = allResults.length;
const highConf = allResults.filter(function(r){return r.matches&&r.matches[0]&&r.matches[0].confidence>=80;}).length;
const noMatch = allResults.filter(function(r){return !r.matches||r.matches.length===0;}).length;

const html = '<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:1000px;margin:0 auto">'
  + '<h2 style="color:#2c3e50">Portland Fuel — Company Name Lookup</h2>'
  + '<p><strong>'+total+'</strong> searched &nbsp;|&nbsp; <strong>'+highConf+'</strong> high-confidence &nbsp;|&nbsp; <strong>'+noMatch+'</strong> not found &nbsp;|&nbsp; '+date+'</p>'
  + '<p style="font-size:12px">'
  + '<span style="background:#d4edda;color:#155724;padding:2px 8px;border-radius:3px;margin-right:6px">High ≥80%</span>'
  + '<span style="background:#fff3cd;color:#856404;padding:2px 8px;border-radius:3px;margin-right:6px">Medium 50–79%</span>'
  + '<span style="background:#f8d7da;color:#721c24;padding:2px 8px;border-radius:3px">Low &lt;50%</span>'
  + '</p>'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">'
  + '<thead><tr style="background:#2c3e50;color:#fff">'
  + '<th style="padding:8px;text-align:left;width:200px">Searched Name</th>'
  + '<th style="padding:8px;width:110px">Reg No</th>'
  + '<th style="padding:8px;text-align:left">Registered Name</th>'
  + '<th style="padding:8px;width:90px;text-align:center">Confidence</th>'
  + '<th style="padding:8px;width:80px">Status</th>'
  + '<th style="padding:8px;text-align:left">Reason</th>'
  + '</tr></thead>'
  + '<tbody>'+htmlRows+'</tbody>'
  + '</table>'
  + '<p style="color:#999;font-size:11px;margin-top:16px">Generated '+new Date().toISOString()+' via n8n / Amelai — full results attached as CSV</p>'
  + '</body></html>';

const csvContent = csvLines.join('\n');
const csvBase64 = Buffer.from(csvContent, 'utf-8').toString('base64');
const subject = 'Company Lookup — '+total+' searched, '+highConf+' high confidence | '+date;

return [{json: {subject: subject, htmlBody: html, csvBase64: csvBase64}}];

const allResults = $('Aggregate').first().json.allResults || [];
const date = new Date().toLocaleDateString('en-GB');
const SYM = {high: '✓', medium: '~', low: '✗'};

const total = allResults.length;
const highConf = allResults.filter(function(r){return r.matches&&r.matches[0]&&r.matches[0].confidence>=80;}).length;
const noMatch = allResults.filter(function(r){return !r.matches||r.matches.length===0;}).length;

let md = '**Portland Fuel — Company Name Lookup** | ' + total + ' searched, ' + highConf + ' high-confidence, ' + noMatch + ' not found | ' + date + '\n\n';
md += '✓ High (≥80%)   ~ Medium (50–79%)   ✗ Low (<50%)\n\n';
md += '| Searched Name | Reg No | Registered Name | Confidence | Status |\n';
md += '|---|---|---|:---:|---|\n';

for (const result of allResults) {
  const name = result.companyName || '';
  if (!result.matches || result.matches.length === 0) {
    md += '| ' + name + ' | — | *No match found* | — | — |\n';
    continue;
  }
  result.matches.forEach(function(m) {
    const sym = SYM[m.confidence_level] || '?';
    md += '| ' + name + ' | ' + sym + ' [' + m.company_number + '](' + m.ch_url + ') | ' + m.company_name + ' | ' + m.confidence + '% | ' + m.status + ' |\n';
  });
}

md += '\n_Full results and CSV sent to steve@portland-fuel.co.uk_';

return [{json: {output: md}}];
